div.script:

    $(document).ready(function() {

        $('.js-example-basic-multiple').select2({
            width: '100%',
            language: {
                noResults: function() {
                    var message = '¡No pudimos encontrar ninguna coincidencia! Para más detalles, ';

                                var div = document.createElement('div');
                                div.textContent = message;  

                                var mailLink = document.createElement('a');
                                mailLink.href = 'mailto:comercial@importadora.com';
                                mailLink.textContent = 'contacte con nuestro equipo comercial.';

                                div.appendChild(mailLink);

                                return div;
                }
            },

        });
        var alimentosDeImportacion = ;
        var selectedProducts = ;


        // Función para cargar las opciones en el select
        function loadSelect2Options(products,selectedProducts) {
            var $select = $('#productRequired');
            $select.empty(); // Limpiar las opciones existentes
            products.forEach(function(product) {

                var isSelected = selectedProducts.includes(parseInt(product.id));
                var newOption = new Option(product.name, product.id, isSelected, isSelected);
                $select.append(newOption);
            });
            $select.trigger('change');
            // Notificar a select2 de los cambios
        }

        loadSelect2Options(alimentosDeImportacion,selectedProducts); 


        console.log("Sincronización de productos lista");


        // Aplicar los estilos del select2 cuando se abre/cierra
        $('.js-example-basic-multiple').on('select2:open', function() {
            $('.select2-selection').addClass('custom-select-focus');
        });

        $('.js-example-basic-multiple').on('select2:close', function() {
            $('.select2-selection').removeClass('custom-select-focus');
        });

        $('#productRequired').on('select2:select', function() {

                $('#hiddenTestInput').trigger("change");

                })
        ;
            $('#productRequired').on('select2:unselect', function() {

                $('#hiddenTestInput').trigger("change");

                })
        ;

        console.log("Select dinámico cargado exitosamente");

        $('.select2-container--default .select2-selection--multiple').css({
            'border': '1px solid  color-mix(in srgb, currentColor 15%, transparent)',
            'font-size': '1rem',
            'padding': '0.375rem 0.75rem',
            'line-height': '1.5',
            'background-color': '#FFFFFF',

        });
        $('.select2-search').css({
            'padding': '0',

        });
        $('.js-example-basic-multiple').on('select2:open', function() {
                $('.select2-selection').addClass('custom-select-focus');
        });

        $('.js-example-basic-multiple').on('select2:close', function() {
                $('.select2-selection').removeClass('custom-select-focus');
        });

        console.log("JS OK 200")
    })
;


$(document).ready(function() {

